const fmtScore = n => {
  if(n>=1e12) return (n/1e12).toFixed(n%1e12===0?0:2)+'兆';
  if(n>=1e8) return (n/1e8).toFixed(n%1e8===0?0:2)+'億';
  if(n>=1e4) return (n/1e4).toFixed(n%1e4===0?0:1)+'万';
  return String(n);
};

const PALETTE = {strawberry:'#FF6F91', mint:'#5FC7A3', lavender:'#9B87F5', gold:'#F2A73B', cocoa:'#4A2E23', cocoaSoft:'#8A6B5C'};

function wrapLabel(text, maxCharsPerLine, maxLines){
  if(!text) return [''];
  const lines = [];
  for(let i=0; i<text.length && lines.length<maxLines; i+=maxCharsPerLine){
    lines.push(text.slice(i, i+maxCharsPerLine));
  }
  if(lines.length===maxLines && text.length > maxLines*maxCharsPerLine){
    lines[maxLines-1] = lines[maxLines-1].slice(0, -1) + '…';
  }
  return lines;
}

/* ---------- HERO STATS ---------- */
function renderHero(){
try{
  const eps = DATA.episodes;
  const numbered = eps.filter(e=>e.ep!=='生配信').length;
  const live = eps.filter(e=>e.ep==='生配信').length;
  const guests = eps.filter(e=>e.guest).length;
  const firstDate = eps.find(e=>e.date)?.date;
  const lastDate = [...eps].reverse().find(e=>e.date)?.date;
  const stats = [
    {num:numbered+'回', lbl:'通常回'},
    {num:live+'回', lbl:'特別生配信'},
    {num:guests+'回', lbl:'ゲスト出演'},
    {num:(firstDate||'').slice(0,7).replace('-','/'), lbl:'配信開始'},
    {num:(lastDate||'').slice(0,7).replace('-','/'), lbl:'記録最終回'},
  ];
  document.getElementById('heroStats').innerHTML = stats.map(s=>`
    <div class="stat-pill"><div class="num">${s.num}</div><div class="lbl">${s.lbl}</div></div>
  `).join('');
}catch(e){console.error('section error:', e);}
}

/* ---------- GOJUON HEATMAP ---------- */
function renderGojuon(){
try{
  const order = ['あ行','か行','が行','さ行','ざ行','た行','だ行','な行','は行','ば行','ぱ行','ま行','や行','ら行','わ行'];
  const kanaOf = {'あ行':'あ','か行':'か','が行':'が','さ行':'さ','ざ行':'ざ','た行':'た','だ行':'だ','な行':'な','は行':'は','ば行':'ば','ぱ行':'ぱ','ま行':'ま','や行':'や','ら行':'ら','わ行':'わ'};
  const map = {};
  DATA.reaction_breakdown.forEach(r=>map[r.label]=r.count);
  const max = Math.max(...Object.values(map));
  document.getElementById('reactTotal').textContent = DATA.reaction_total;
  const html = order.map(label=>{
    const c = map[label]||0;
    const t = max? c/max : 0;
    // interpolate cream -> strawberry
    const bg = c===0 ? '#FBE8D3' : mix('#FBE8D3', '#FF6F91', t);
    const fg = t>0.55 ? '#fff' : '#4A2E23';
    return `<div class="goj-tile" style="background:${bg}; color:${fg};">
      <span class="kana">${kanaOf[label]}</span>
      <span class="gyo" style="color:${t>0.55?'rgba(255,255,255,.85)':'#8A6B5C'}">${label}</span>
      <span class="cnt">${c}</span>
    </div>`;
  }).join('');
  document.getElementById('gojuonGrid').innerHTML = html;

  function mix(hexA, hexB, t){
    const a = hexToRgb(hexA), b = hexToRgb(hexB);
    const r = Math.round(a[0]+(b[0]-a[0])*t);
    const g = Math.round(a[1]+(b[1]-a[1])*t);
    const bl = Math.round(a[2]+(b[2]-a[2])*t);
    return `rgb(${r},${g},${bl})`;
  }
  function hexToRgb(h){
    h = h.replace('#','');
    return [parseInt(h.slice(0,2),16), parseInt(h.slice(2,4),16), parseInt(h.slice(4,6),16)];
  }
}catch(e){console.error('section error:', e);}
}

/* ---------- ICE CREAM SECTION ---------- */
function renderIce(){
try{
  const s = DATA.ice_stats;
  const cards = [
    {cls:'max', kicker:'最大値 MAX', val:fmtScore(s.max_val)+'点', name:s.max_item, desc:s.max_desc},
    {cls:'med', kicker:'中央値 MEDIAN', val:fmtScore(s.median_val)+'点', name:s.median_item, desc:s.median_desc},
    {cls:'min', kicker:'最小値 MIN', val:fmtScore(s.min_val)+'点', name:s.min_item, desc:s.min_desc},
  ];
  document.getElementById('iceHighlights').innerHTML = cards.map(c=>`
    <div class="highlight-card ${c.cls}">
      <div class="kicker">${c.kicker}</div>
      <div class="val">${c.val}</div>
      <div class="name">${(c.name||'').replace(/\n/g,' ')}</div>
      <div class="desc">${(c.desc||'').replace(/\n/g,' ')}</div>
    </div>
  `).join('');

  const scored = DATA.ice_list.filter(x=>x.score_num).sort((a,b)=>b.score_num-a.score_num).slice(0,18);
  const iceLabels = scored.map(x=>(x.ep||'')+' '+(x.name||'').replace(/\n/g,' '));
  Chart.getChart('iceChart')?.destroy();
  new Chart(document.getElementById('iceChart'), {
    type:'bar',
    data:{
      labels: iceLabels,
      datasets:[{
        data: scored.map(x=>x.score_num),
        backgroundColor: PALETTE.strawberry,
        borderRadius:8,
        maxBarThickness:22,
      }]
    },
    options:{
      maintainAspectRatio:false,
      responsive:true,
      indexAxis:'y',
      responsive:true,
      plugins:{
        legend:{display:false},
        tooltip:{callbacks:{label:(ctx)=>fmtScore(ctx.raw)+'点'}}
      },
      scales:{
        x:{type:'logarithmic', ticks:{callback:(v)=>{
            const s=String(v);
            if(['100','1000','10000','100000','1000000','10000000','100000000','1000000000','10000000000','100000000000'].includes(s)) return fmtScore(v);
            return null;
          }}, grid:{color:'rgba(74,46,35,0.08)'}},
        y:{grid:{display:false}, ticks:{font:{size:11}, callback:(val,idx)=>wrapLabel(iceLabels[idx], 13, 2)}}
      }
    }
  });
}catch(e){console.error('section error:', e);}
}

/* ---------- CORNER SECTION ---------- */
function renderCorner(){
try{
  document.getElementById('cornerEpCount').textContent = DATA.episodes.length;
  const totals = DATA.corner_totals;
  const labels = Object.keys(totals);
  const cornerValueLabels = {
    id: 'cornerValueLabels',
    afterDatasetsDraw(chart){
      const {ctx} = chart;
      const meta = chart.getDatasetMeta(0);
      ctx.save();
      ctx.fillStyle = PALETTE.cocoa;
      ctx.font = "500 11px 'DM Mono', monospace";
      ctx.textAlign = 'left';
      ctx.textBaseline = 'middle';
      meta.data.forEach((bar, i) => {
        ctx.fillText(chart.data.datasets[0].data[i], bar.x + 8, bar.y);
      });
      ctx.restore();
    }
  };
  Chart.getChart('cornerChart')?.destroy();
  new Chart(document.getElementById('cornerChart'), {
    type:'bar',
    data:{
      labels,
      datasets:[{
        data: labels.map(l=>totals[l]),
        backgroundColor: [PALETTE.strawberry, PALETTE.mint, PALETTE.lavender, PALETTE.gold, '#E8B4C8','#7FB6A8','#B7A6E8','#F0C88A','#D9A7B0'],
        borderRadius:8,
        maxBarThickness:30,
      }]
    },
    options:{
      maintainAspectRatio:false,
      responsive:true,
      indexAxis:'y',
      layout:{padding:{right:28}},
      plugins:{legend:{display:false}},
      scales:{x:{grid:{color:'rgba(74,46,35,0.08)'}}, y:{grid:{display:false}, ticks:{font:{size:11}, callback:(val,idx)=>wrapLabel(labels[idx], 9, 2)}}}
    },
    plugins:[cornerValueLabels]
  });

  const lastEpDate = DATA.episodes.map(e=>e.date).filter(Boolean).sort().pop();
  const lastEpMonth = lastEpDate ? lastEpDate.slice(2,4) + '/' + lastEpDate.slice(5,7) : null;
  const monthlyTrimmed = lastEpMonth
    ? DATA.monthly_corners.filter(m => m.month <= lastEpMonth)
    : DATA.monthly_corners;
  const months = monthlyTrimmed.map(m=>m.month);
  const keys = ['今週のアイス','花岩香奈は叶えたい！','リアクションのあいうえお','これ知ってるカナ！？'];
  const colors = [PALETTE.strawberry, PALETTE.mint, PALETTE.lavender, PALETTE.gold];

  const monthlyLegendEl = document.getElementById('monthlyLegend');
  if(monthlyLegendEl){
    monthlyLegendEl.innerHTML = keys.map((k,i)=>`
      <span class="legend-item"><span class="legend-dot" style="background:${colors[i]}"></span>${k}</span>
    `).join('');
  }

  Chart.getChart('monthlyChart')?.destroy();
  new Chart(document.getElementById('monthlyChart'), {
    type:'bar',
    data:{
      labels: months,
      datasets: keys.map((k,i)=>({
        label:k,
        data: monthlyTrimmed.map(m=>m[k]||0),
        backgroundColor: colors[i],
        borderRadius:4,
        maxBarThickness:38,
      }))
    },
    options:{
      maintainAspectRatio:false,
      responsive:true,
      layout:{padding:{top:10}},
      plugins:{legend:{display:false}},
      scales:{
        x:{stacked:true, grid:{display:false}, ticks:{autoSkip:false, maxRotation:0, minRotation:0}},
        y:{stacked:true, beginAtZero:true, grid:{color:'rgba(74,46,35,0.08)'}, ticks:{display:false}}
      }
    }
  });

  Chart.getChart('monthlyAxisChart')?.destroy();
  new Chart(document.getElementById('monthlyAxisChart'), {
    type:'bar',
    data:{
      labels: months,
      datasets: keys.map((k,i)=>({
        label:k,
        data: monthlyTrimmed.map(m=>m[k]||0),
        backgroundColor: 'transparent',
        borderWidth:0,
      }))
    },
    options:{
      maintainAspectRatio:false,
      responsive:true,
      animation:false,
      layout:{padding:{top:10, bottom:3}},
      plugins:{legend:{display:false}, tooltip:{enabled:false}},
      scales:{
        x:{stacked:true, grid:{display:false}, ticks:{color:'transparent', font:{size:11}, autoSkip:false, maxRotation:0, minRotation:0}},
        y:{stacked:true, beginAtZero:true, grid:{display:false}, ticks:{font:{size:11}}}
      }
    }
  });
}catch(e){console.error('section error:', e);}
}

/* ---------- CHARACTER SECTION ---------- */
function renderChar(){
try{
  const cc = DATA.char_counts;
  Chart.getChart('charChart')?.destroy();
  new Chart(document.getElementById('charChart'), {
    type:'bar',
    data:{
      labels: cc.map(c=>c.name),
      datasets:[{
        data: cc.map(c=>c.count),
        backgroundColor: PALETTE.lavender,
        borderRadius:8,
        maxBarThickness:22,
      }]
    },
    options:{
      maintainAspectRatio:false,
      responsive:true,
      indexAxis:'y',
      plugins:{legend:{display:false}},
      scales:{x:{grid:{color:'rgba(74,46,35,0.08)'}, ticks:{stepSize:1}}, y:{grid:{display:false}}}
    }
  });
}catch(e){console.error('section error:', e);}
}

/* ---------- QUIZ SECTION ---------- */
function renderQuiz(){
try{
  const q = DATA.quiz_stats;
  const items = [
    {n:q.count, l:'採点数'},
    {n:q.mean.toFixed(1), l:'平均点'},
    {n:q.median, l:'中央値'},
    {n:q.std.toFixed(1), l:'標準偏差'},
    {n:q.max, l:'最高点'},
    {n:q.min, l:'最低点'},
  ];
  document.getElementById('quizStats').innerHTML = items.map(i=>`
    <div class="qs-item"><div class="n">${i.n}</div><div class="l">${i.l}</div></div>
  `).join('');

  const scores = DATA.quiz_entries.map(e=>e.score);
  const BUCKET_SIZE = 25;
  const maxScore = Math.max(...scores);
  const bucketCount = Math.ceil((maxScore + 1) / BUCKET_SIZE);
  const buckets = Array.from({length: bucketCount}, (_,i)=>[i*BUCKET_SIZE, (i+1)*BUCKET_SIZE]);
  const bucketLabels = buckets.map(([lo,hi])=>`${lo}〜${hi}`);
  const counts = buckets.map(([lo,hi])=>scores.filter(s=>s>=lo && s<hi).length);
  const isNarrow = window.matchMedia('(max-width: 700px)').matches;
  const xTicks = isNarrow
    ? {maxRotation:0, minRotation:0, autoSkip:true, maxTicksLimit:7, font:{size:10}}
    : {maxRotation:60, minRotation:0, autoSkip:false, font:{size:10}};
  Chart.getChart('quizChart')?.destroy();
  new Chart(document.getElementById('quizChart'), {
    type:'bar',
    data:{
      labels: bucketLabels,
      datasets:[{data:counts, backgroundColor: PALETTE.mint, borderRadius:8, maxBarThickness:46}]
    },
    options:{
      maintainAspectRatio:false,
      responsive:true,
      plugins:{legend:{display:false}},
      scales:{y:{beginAtZero:true, ticks:{stepSize:1}, grid:{color:'rgba(74,46,35,0.08)'}}, x:{grid:{display:false}, ticks:xTicks}}
    }
  });
}catch(e){console.error('section error:', e);}
}

/* ---------- EPISODE ARCHIVE ---------- */
const REMARK_FIELDS = [
  {key:'voice_info', label:'声優/いわ情報'},
  {key:'iwa_detail', label:'いわ情報詳細'},
  {key:'wish_chara', label:'叶えたいキャラ'},
  {key:'letter', label:'おたより採用'},
  {key:'theme_change', label:'テーマ変化'},
  {key:'chichibu', label:'秩父情報'},
  {key:'memo', label:'備考'},
];

function renderArchive(){
try{
  const eps = DATA.episodes;
  const cornerKeys = Object.keys(eps[0].corners);
  const sel = document.getElementById('cornerFilter');
  const prevSel = sel.value;
  sel.innerHTML ='<option value="">すべてのコーナー</option>' +cornerKeys.map(k => {const label = (k === 'あいうえお') ? 'リアクションのあいうえお' : k;return `<option value="${k}">${label}</option>`;}).join('');  if(cornerKeys.includes(prevSel)) sel.value = prevSel;

  function renderList(){
    const eps = DATA.episodes;
    const cornerKeys = Object.keys(eps[0].corners);
    const q = document.getElementById('searchBox').value.trim().toLowerCase();
    const cf = sel.value;
    const filtered = eps.filter(e=>{
      if(cf && !e.corners[cf]) return false;
      if(!q) return true;
      const hay = [e.ep,e.title,e.ice,e.guest,e.special,e.memo,e.aiueo,e.wish_chara,e.voice_info,e.iwa_detail].filter(Boolean).join(' ').toLowerCase();
      return hay.includes(q);
    });
    document.getElementById('epCount').textContent = `${filtered.length} / ${eps.length} 回を表示`;
    document.getElementById('emptyState').style.display = filtered.length? 'none':'block';
    document.getElementById('epList').innerHTML = filtered.map(e=>{
      const idx = eps.indexOf(e);
      const badges = cornerKeys.filter(k=>e.corners[k]).map(k=>`<span class="badge on">${k}</span>`).join('');
      const guestBadge = e.guest? `<span class="badge guest">ゲスト: ${e.guest.replace(/\n/g,' ')}</span>`:'';
      const specialBadge = e.special? `<span class="badge special">${e.special.replace(/\n/g,' ')}</span>`:'';
      const scoreBadge = e.ice_score_text? `<div class="ice-score-badge">🎯 ${e.ice_score_text.replace(/\n/g,' ')}</div>` : '';
      return `<div class="ep-card" data-idx="${idx}">
        <div class="row-top">
          <span class="ep-num">${e.ep}</span>
          <span class="ep-date">${e.date||''}</span>
        </div>
        <div class="ep-title">${e.title? e.title.replace(/\n/g,' ') : '（タイトルなし）'}</div>
        <div class="ep-meta">${e.ice? '🍦 <b>'+e.ice.replace(/\n/g,' ')+'</b>':''}</div>
        ${scoreBadge}
        <div class="badge-row">${badges}${guestBadge}${specialBadge}</div>
      </div>`;
    }).join('');
  }
  window._archiveRenderList = renderList;
  renderList();

  if(!window._archiveEventsBound){
    window._archiveEventsBound = true;
    document.getElementById('searchBox').addEventListener('input', ()=>window._archiveRenderList());
    document.getElementById('cornerFilter').addEventListener('change', ()=>window._archiveRenderList());
    function setHashSilently(hash){
      if(hash){
        history.pushState({epIdx: hash}, '', '#' + hash);
      } else if(location.hash){
        history.pushState({}, '', location.pathname + location.search);
      }
    }

    function lockScroll(){
      if(document.body.dataset.locked === '1') return;
      const y = window.scrollY;
      document.body.dataset.scrollY = y;
      document.body.dataset.locked = '1';
      document.body.style.position = 'fixed';
      document.body.style.top = (-y) + 'px';
      document.body.style.left = '0';
      document.body.style.right = '0';
    }
    function unlockScroll(){
      if(document.body.dataset.locked !== '1') return;
      const y = parseInt(document.body.dataset.scrollY || '0', 10);
      document.body.dataset.locked = '0';
      document.body.style.position = '';
      document.body.style.top = '';
      document.body.style.left = '';
      document.body.style.right = '';
      window.scrollTo(0, y);
      requestAnimationFrame(()=>{ window.scrollTo(0, y); });
    }

    document.getElementById('epList').addEventListener('click', (ev)=>{
      const card = ev.target.closest('.ep-card');
      if(!card) return;
      lockScroll();
      setHashSilently('ep-' + card.dataset.idx);
      showDetail(parseInt(card.dataset.idx, 10));
    });

    const overlay = document.getElementById('detailOverlay');

    function closeDetailNav(){
      setHashSilently(null);
      hideDetail();
    }

    function showDetail(idx){
      const eps = DATA.episodes;
      const cornerKeys = Object.keys(eps[0].corners);
      const e = eps[idx];
      if(!e){ closeDetailNav(); return; }
      const badges = cornerKeys.filter(k=>e.corners[k]).map(k=>`<span class="badge on">${k}</span>`).join('');
      const guestBadge = e.guest? `<span class="badge guest">ゲスト: ${e.guest.replace(/[\r\n]+/g,' ')}</span>`:'';
      const specialBadge = e.special? `<span class="badge special">${e.special.replace(/[\r\n]+/g,' ')}</span>`:'';
      const remarksHtml = REMARK_FIELDS.filter(f=>e[f.key]).map(f=>`
        <div class="detail-section">
          <span class="dt-label">${f.label}</span>
          <div class="dt-val">${e[f.key].replace(/\n/g,'\n')}</div>
        </div>
      `).join('');
      const remarksBlock = remarksHtml || `<div class="detail-section"><span class="dt-label">備考</span><div class="dt-val">この回には備考の記載はありません。</div></div>`;
      const iceHtml = e.ice ? `
        <div class="detail-ice">
          🍦 <b>${e.ice.replace(/\n/g,' ')}</b>
          ${e.ice_score_text? '<br><span class="mono">🎯 '+e.ice_score_text.replace(/\n/g,' ')+'</span>' : ''}
        </div>` : '';
      document.getElementById('detailContent').innerHTML = `
        <div class="detail-head">
          <span class="ep-num">${e.ep}</span><span class="ep-date">${e.date||''}</span>
          <h3>${e.title? e.title.replace(/\n/g,' ') : '（タイトルなし）'}</h3>
          ${e.url? `<a class="listen-link" href="${e.url}" target="_blank" rel="noopener noreferrer">▶ この回を聴く</a>` : ''}
        </div>
        ${iceHtml}
${e.aiueo ? `<div class="detail-section"><span class="dt-label">リアクションのあいうえお</span><div class="dt-val">${String(e.aiueo).replace(/\n/g,'\n')}</div></div>` : ''}
        ${e.ojisan? `<div class="detail-section"><span class="dt-label">おじさん構文評価</span><div class="dt-val">${e.ojisan.replace(/\n/g,'\n')}</div></div>`:''}
        ${remarksBlock}
        <div class="detail-badges badge-row">${badges}${guestBadge}${specialBadge}</div>
      `;
      overlay.classList.add('open');
      overlay.setAttribute('aria-hidden','false');
      lockScroll();
      overlay.scrollTop = 0;
    }

    function hideDetail(){
      if(overlay.contains(document.activeElement)){
        document.activeElement.blur();
      }
      overlay.classList.remove('open');
      overlay.setAttribute('aria-hidden','true');
      unlockScroll();
    }

    function syncFromHash(){
      const m = location.hash.match(/^#ep-(\d+)$/);
      if(m){ showDetail(parseInt(m[1],10)); } else { hideDetail(); }
    }
    window.addEventListener('popstate', syncFromHash);
    overlay.addEventListener('click', (ev)=>{
      if(ev.target.closest('[data-close]')){ closeDetailNav(); }
    });
    document.addEventListener('keydown', (ev)=>{ if(ev.key==='Escape') closeDetailNav(); });
    syncFromHash();
  }
}catch(e){console.error('section error:', e);}
}

