/* ============================================================
   LIVE XLSX SYNC
   Fetches the xlsx file (expected to sit next to this HTML file,
   e.g. in the same GitHub repo / Cloudflare Pages deployment) at
   load time. If found and parseable, rebuilds DATA from it and
   re-renders everything. Falls back silently to the embedded
   snapshot on any failure (missing file, local file:// testing,
   parse error, structure mismatch).
   ============================================================ */
const XLSX_FILENAME = 'はないわーるど.xlsx';

function setSyncStatus(text, cls){
  const el = document.getElementById('syncStatus');
  if(!el) return;
  el.textContent = text;
  el.className = 'sync-status ' + (cls || '');
}

function cleanVal(v){
  if(v === undefined || v === null) return null;
  if(typeof v === 'string'){
    const t = v.trim();
    if(t === '' || t === '-') return null;
    return t;
  }
  return v;
}
function toDateStr(v){
  if(v === undefined || v === null) return null;
  let d;
  if(v instanceof Date) d = v;
  else if(typeof v === 'number') d = new Date(Math.round((v - 25569) * 86400 * 1000));
  else return null;
  if(isNaN(d.getTime())) return null;
  const y = d.getUTCFullYear(), m = String(d.getUTCMonth()+1).padStart(2,'0'), day = String(d.getUTCDate()).padStart(2,'0');
  return `${y}-${m}-${day}`;
}
function numOrNull(v){
  if(v === null || v === undefined || v === '') return null;
  const n = Number(v);
  return isNaN(n) ? null : n;
}
function sheetGrid(wb, name){
  const ws = wb.Sheets[name];
  if(!ws) throw new Error('シートが見つかりません: ' + name);
  return XLSX.utils.sheet_to_json(ws, {header:1, raw:true, defval:null});
}

function buildDataFromWorkbook(wb){
  const cornerNamesJp = ['フリートーク','今週のアイス','花岩香奈は叶えたい！','リアクションのあいうえお',
                          'これ知ってるカナ！？','お祝いいわちゃん','今週の秩父の話',
                          'いわちゃんのこんな投稿見てみたい！','はないわーるどオノマトペ！'];
  const cornerCols = ['花岩香奈は叶えたい！','リアクションのあいうえお','これ知ってるカナ！？',
                       'お祝いいわちゃん！','今週の秩父の話','こんな投稿見てみたい！','はないわーるどオノマトペ！'];

  // ---- 全まとめ (column order flexible: looked up by name) ----
  const mainGrid = sheetGrid(wb, '全まとめ');
  const headerRow = mainGrid[1] || [];
  const colIdx = {};
  headerRow.forEach((h,i)=>{ if(h!=null) colIdx[String(h).replace(/\n/g,'')] = i; });
  const TITLE_KEY = ('タイトル' in colIdx) ? 'タイトル' : 'フリートーク';
  const missingCols = cornerCols.filter(c => colIdx[c] === undefined);
  if(missingCols.length > 0) throw new Error('全まとめシートの列名が見つかりません: ' + missingCols.join('、'));
  const get = (row, name) => (colIdx[name]!=null) ? row[colIdx[name]] : undefined;

  const episodes = [];
  for(let r=2; r<mainGrid.length; r++){
    const row = mainGrid[r] || [];
    const hasContent = [TITLE_KEY,'今週のアイス','あいうえお','ゲスト','特別企画','メモ']
      .some(k => cleanVal(get(row,k)) !== null);
    if(!hasContent) continue;
    const corners = {};
    cornerCols.forEach(c=>{ corners[c] = !!get(row,c); });
    episodes.push({
      ep: cleanVal(get(row,'回')),
      date: toDateStr(get(row,'日付')),
      title: cleanVal(get(row,TITLE_KEY)),
      ice: cleanVal(get(row,'今週のアイス')),
      aiueo: cleanVal(get(row,'あいうえお')),
      ojisan: cleanVal(get(row,'おじさん構文評価')),
      wish_chara: cleanVal(get(row,'叶えたいキャラ')),
      guest: cleanVal(get(row,'ゲスト')),
      special: cleanVal(get(row,'特別企画')),
      memo: cleanVal(get(row,'メモ')),
      theme_change: cleanVal(get(row,'テーマ変化')),
      chichibu: cleanVal(get(row,'秩父情報')),
      voice_info: cleanVal(get(row,'○○声優/いわ情報')),
      iwa_detail: cleanVal(get(row,'いわ情報詳細')),
      letter: cleanVal(get(row,'おたより採用')),
      url: cleanVal(get(row,'URL')),
      corners
    });
  }
  if(episodes.length === 0) throw new Error('全まとめシートから回を読み取れませんでした');

  // ---- 今週のアイスまとめ (fixed positions) ----
  const iceGrid = sheetGrid(wb, '今週のアイスまとめ');
  const ice_list = [];
  for(let r=1; r<iceGrid.length; r++){
    const row = iceGrid[r] || [];
    const name = cleanVal(row[2]);
    const score_text = cleanVal(row[3]);
    const score_num = numOrNull(row[4]);
    const ep = cleanVal(row[0]);
    if(ep===null && name===null) continue;
    ice_list.push({ep, date: toDateStr(row[1]), name, score_text, score_num});
  }
  const iceRow = (i) => iceGrid[i] || [];
  const ice_stats = {
    max_val: numOrNull(iceRow(1)[8]), max_item: cleanVal(iceRow(1)[9]), max_desc: cleanVal(iceRow(1)[10]),
    min_val: numOrNull(iceRow(2)[8]), min_item: cleanVal(iceRow(2)[9]), min_desc: cleanVal(iceRow(2)[10]),
    median_val: numOrNull(iceRow(3)[8]), median_item: cleanVal(iceRow(3)[9]), median_desc: cleanVal(iceRow(3)[10]),
  };

  // ---- 叶えたい！キャラ一覧 ----
  const charGrid = sheetGrid(wb, '叶えたい！キャラ一覧');
  const char_counts = [];
  for(let r=1; r<charGrid.length; r++){
    const row = charGrid[r] || [];
    const name = cleanVal(row[6]);
    const cnt = numOrNull(row[7]);
    if(name===null || cnt===null) continue;
    char_counts.push({name, count: Math.round(cnt)});
  }

  // ---- リアクション統計 (no header row) ----
  const reactGrid = sheetGrid(wb, 'リアクション統計');
  let reaction_total = null;
  const reaction_breakdown = [];
  for(const row of reactGrid){
    const label = cleanVal(row[0]);
    const val = numOrNull(row[1]);
    if(label===null || val===null) continue;
    if(label==='総数') reaction_total = Math.round(val);
    else reaction_breakdown.push({label, count: Math.round(val)});
  }

  // ---- 知ってるカナ点数計算 ----
  const quizGrid = sheetGrid(wb, '知ってるカナ点数計算');
  const quiz_entries = [];
  for(let r=1; r<quizGrid.length; r++){
    const row = quizGrid[r] || [];
    const topic = cleanVal(row[2]);
    const score = numOrNull(row[3]);
    if(topic===null || score===null) continue;
    quiz_entries.push({ep: cleanVal(row[0]), topic, score});
  }
  const quizRow = (i) => quizGrid[i] || [];
  const quiz_stats = {
    count: Math.round(numOrNull(quizRow(0)[7])),
    mean: numOrNull(quizRow(1)[7]),
    median: numOrNull(quizRow(2)[7]),
    std: numOrNull(quizRow(3)[7]),
    max: numOrNull(quizRow(4)[7]),
    min: numOrNull(quizRow(5)[7]),
  };

  // ---- コーナー出現分布 ----
  const cornerGrid = sheetGrid(wb, 'コーナー出現分布');
  const corner_totals = {};
  cornerNamesJp.forEach((name,i)=>{
    const c = 2+i;
    let sum = 0;
    for(let r=1; r<cornerGrid.length; r++){
      const v = numOrNull((cornerGrid[r]||[])[c]);
      if(v!==null) sum += v;
    }
    corner_totals[name] = sum;
  });
  const monthly_corners = [];
  for(let r=1; r<cornerGrid.length; r++){
    const row = cornerGrid[r] || [];
    const m = cleanVal(row[13]);
    if(m===null) continue;
    const entry = {month: m};
    cornerNamesJp.forEach((name,i)=>{
      const v = numOrNull(row[14+i]);
      entry[name] = v===null ? 0 : Math.round(v);
    });
    monthly_corners.push(entry);
  }

  // ---- join ice scores onto episodes (match by ep + date) ----
  const iceByKey = {};
  ice_list.forEach(it => { iceByKey[it.ep + '|' + it.date] = it; });
  episodes.forEach(ep => {
    const m = iceByKey[ep.ep + '|' + ep.date];
    ep.ice_score_text = m ? m.score_text : null;
    ep.ice_score_num = m ? m.score_num : null;
  });

  return {episodes, ice_list, ice_stats, char_counts, reaction_total, reaction_breakdown,
          quiz_entries, quiz_stats, corner_totals, monthly_corners};
}

async function fetchXlsxData(){
  const url = encodeURI(XLSX_FILENAME) + '?t=' + Date.now();
  const res = await fetch(url, {cache:'no-store'});
  if(!res.ok) throw new Error('HTTP ' + res.status);
  const buf = await res.arrayBuffer();
  const wb = XLSX.read(buf, {type:'array', cellDates:true});
  return buildDataFromWorkbook(wb);
}

(async function syncFromXlsx(){
  try{
    const newData = await fetchXlsxData();
    DATA = newData;
    renderAll();
    const n = newData.episodes.length;
    const last = newData.episodes[n-1];
    setSyncStatus(`✅ 最新のExcelデータを反映しました（全${n}話 / 最新: ${last.ep} ${last.date||''}）`, 'live');
  }catch(e){
    console.warn('xlsx live sync failed, showing embedded snapshot instead:', e);
    setSyncStatus('⚠️ Excelファイル（' + XLSX_FILENAME + '）を取得できなかったため、保存済みのデータを表示しています', 'offline');
  }
})();

